+export function sequenceMaybeAsResult<T extends {}, E>(
+  errValue: E, maybes?: Iterable<Maybe<T>>
+): Result<T[], E> | ((maybes: Iterable<Maybe<T>>) => Result<T[], E>) {
+  const op = (items: Iterable<Maybe<T>>) => {
+    const values: T[] = [];
+    for (const maybe of items) {
+      if (maybe.isNothing) return Result.err<T[], E>(errValue);
+      values.push(maybe.value);
+    }
+    return Result.ok<T[], E>(values);
+  };
+  return maybes === undefined ? op : op(maybes);
